INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47c26ff2-e8f9-4fe3-9718-d79f6a0f9407', $q$What does Vendr do?$q$, $q$Vendr is a SaaS buying and pricing intelligence platform that helps finance and procurement teams benchmark software prices and negotiate better contract terms.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47c26ff2-e8f9-4fe3-9718-d79f6a0f9407', $q$When was Vendr founded?$q$, $q$Vendr was started in 2018 and went through Y Combinator's Summer 2019 batch.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47c26ff2-e8f9-4fe3-9718-d79f6a0f9407', $q$Where is Vendr headquartered?$q$, $q$Vendr is headquartered in Boston, Massachusetts, with a second office in Charleston.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47c26ff2-e8f9-4fe3-9718-d79f6a0f9407', $q$Has Vendr been acquired?$q$, $q$Yes, Vendr was acquired by Vertice, a competing SaaS spend management platform, effective June 1, 2026.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47c26ff2-e8f9-4fe3-9718-d79f6a0f9407', $q$How much does Vendr cost?$q$, $q$Vendr does not publish self-service pricing; access is sold through custom quotes typically based on a company's total software spend under management.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47c26ff2-e8f9-4fe3-9718-d79f6a0f9407', $q$What data does Vendr use for pricing benchmarks?$q$, $q$Vendr draws on a proprietary dataset described as more than 15 billion dollars in verified software transactions and over 130,000 real negotiations across more than 4,500 suppliers.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47c26ff2-e8f9-4fe3-9718-d79f6a0f9407', $q$Who are Vendr's competitors?$q$, $q$Vendr competes with SaaS spend management and procurement platforms such as Tropic, Zylo, and its acquirer, Vertice.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('47c26ff2-e8f9-4fe3-9718-d79f6a0f9407', $q$Software Purchase Benchmarking$q$, $q$Finance and procurement teams use Vendr to see what comparable companies pay for a given software product before starting negotiations.$q$, $q$Finance and procurement teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('47c26ff2-e8f9-4fe3-9718-d79f6a0f9407', $q$Contract Renewal Negotiation$q$, $q$Companies use Vendr's negotiation tools and agents to secure better pricing and terms on upcoming SaaS contract renewals.$q$, $q$IT asset management and procurement teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('47c26ff2-e8f9-4fe3-9718-d79f6a0f9407', $q$SaaS Spend Consolidation and Oversight$q$, $q$Finance leaders use Vendr to centralize visibility into software contracts, spend, and renewal timing across the organization.$q$, $q$CFOs and finance operations leaders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('47c26ff2-e8f9-4fe3-9718-d79f6a0f9407', $q$Platform Access$q$, $q$Custom quote$q$, $q$annual$q$, NULL, $q$["Pricing Intelligence Agent","Renewal tracking","Contract analysis","API integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('47c26ff2-e8f9-4fe3-9718-d79f6a0f9407', $q$Negotiation Services$q$, $q$Custom quote$q$, $q$per engagement or annual$q$, NULL, $q$["Negotiation Agent for supplier outreach","Human-assisted negotiation for complex deals","Access to verified transaction benchmark data"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('47c26ff2-e8f9-4fe3-9718-d79f6a0f9407', $q$overview$q$, $q$What Is Vendr$q$, 2, ARRAY[$q$Vendr is a software procurement platform that helps companies figure out what they should be paying for SaaS products and negotiate better deals on new purchases and renewals. It was built around the insight that most companies overpay for software because they lack visibility into what similar buyers actually pay.$q$, $q$The company was started in 2018 and went through Y Combinator's Summer 2019 cohort. It raised a series of venture rounds, including a 60 million dollar Series A led by Tiger Global and a 150 million dollar Series B co-led by Craft Ventures and SoftBank Vision Fund, for total funding above 216 million dollars, and is headquartered in Boston, Massachusetts.$q$, $q$Vendr's original product had its own team of negotiators buy software on behalf of customers directly. The company later broadened into a self-serve software platform, Vendr 2.0, launched in 2022, and more recently layered in AI agents for pricing benchmarking and supplier negotiation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('47c26ff2-e8f9-4fe3-9718-d79f6a0f9407', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Vendr's Pricing Intelligence Agent gives buyers real-time benchmark pricing for a given software product based on the company's dataset of more than 15 billion dollars in verified transactions and over 130,000 negotiations, so buyers know what a fair price looks like before entering a negotiation.$q$, $q$The Negotiation Agent can autonomously handle supplier email negotiations, managing counteroffers and terms without requiring buyers to sit in on every call, which Vendr reports achieves roughly an 87 percent success rate across its negotiations.$q$, $q$The platform also includes contract analysis to flag overcharges and negotiable terms in existing agreements, plus integrations with procurement and finance workflows through its API.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('47c26ff2-e8f9-4fe3-9718-d79f6a0f9407', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Vendr does not publish self-service pricing for its own platform; access is sold through custom quotes typically scoped to a customer's total software spend under management, consistent with how similar SaaS spend management platforms like Tropic and Zylo price their services.$q$, $q$Vendr has historically also offered negotiation-as-a-service engagements, where its team directly negotiates specific software contracts on a customer's behalf, in addition to platform-only subscription access.$q$]::text[], 2);
