-- Enrichment marathon batch: Valkey, Vanta, Vector, Vectr, VEED, Velociraptor, Veloren, Vendr

-- ── Valkey ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Valkey is a free, open-source, in-memory key-value data store forked from Redis in 2024 and governed by the Linux Foundation, used for caching, message queues, and as a primary database.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2024, founded_year),
  company_size = COALESCE($q$Open-source project under the Linux Foundation, with roughly 50 contributing companies$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA (Linux Foundation)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Valkey: The Open-Source Redis Fork Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$Valkey is a free, BSD-licensed, Linux Foundation-backed fork of Redis for caching, messaging, and data storage. See features, history, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Valkey is an open-source, in-memory key-value data store used for caching, message queuing, and as a primary database, functioning as a drop-in replacement for Redis. It was created in March 2024 after Redis Inc. changed the licensing of Redis from the permissive BSD 3-Clause license to the source-available RSALv2 and SSPLv1 dual license starting with Redis 7.4, a move that was not recognized as open source by the Open Source Initiative. In response, the Linux Foundation announced Valkey as a community-governed fork built on the last BSD-licensed Redis codebase, version 7.2.4. Six founding maintainers from six different companies led the fork: Zhao Zhao (Alibaba), BinBin Zhu (Tencent), Viktor Soderqvist (Ericsson), Lucas Yang (Huawei), Ping Xie (Oracle, ex-Google), and Madelyn Olson (Amazon). Within its first year, Valkey grew to nearly 50 contributing companies, including AWS, Google Cloud, Oracle, ByteDance, Alibaba Cloud, Percona, Aiven, and DigitalOcean, and surpassed thousands of commits, 150-plus contributors, and millions of Docker pulls. Valkey supports the familiar Redis data structures, including strings, hashes, lists, sets, sorted sets, bitmaps, and hyperloglogs, along with clustering, replication, Lua scripting, and a module system for extensibility. Because it remains BSD 3-Clause licensed, it is free to self-host, embed, and redistribute without the license restrictions that apply to newer Redis versions. Valkey competes directly with Redis, including Redis's own AGPLv3 open-source option introduced with Redis 8, as well as managed alternatives like AWS ElastiCache for Valkey, Google Cloud Memorystore, Upstash, and Aiven for Valkey. Its main draw is licensing certainty backed by neutral foundation governance rather than a single vendor, making it attractive to cloud providers and enterprises wary of future license changes.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '48bf1eae-a2e1-4a2b-99ed-b79c030ae0e8';

