-- ── Vanta ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Vanta is a security and compliance automation platform that continuously monitors a company's systems to help it achieve and maintain certifications such as SOC 2, ISO 27001, HIPAA, and GDPR.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE($q$From approximately $10,000/year (custom quote-based pricing)$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$Approximately 700 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Vanta: Automated Security and Compliance Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Vanta automates SOC 2, ISO 27001, HIPAA, and GDPR compliance with continuous monitoring, evidence collection, and AI-assisted questionnaires.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Vanta is a trust and compliance management platform that automates the manual work of achieving and maintaining security certifications and regulatory compliance. Founded in 2018 by Christina Cacioppo and Erik Goldman, both former Dropbox employees, Vanta went through Y Combinator before growing into one of the leading players in the compliance automation category, alongside competitors like Drata, Secureframe, and Sprinto. The company is headquartered in San Francisco, California, with additional hubs in New York, Dublin, and Sydney, and employs roughly 700 people. Vanta connects to a company's cloud infrastructure, HR systems, version control, and other tools through more than 400 integrations to continuously monitor security controls, automatically collect audit evidence, and flag compliance gaps in real time, rather than relying on the point-in-time spreadsheet audits that were previously standard. It supports frameworks including SOC 2, ISO 27001, HIPAA, GDPR, PCI DSS, HITRUST, ISO 42001, NIST AI RMF, FedRAMP, and CMMC, and also offers third-party vendor risk management, a public-facing Trust Center for sharing security posture with prospects, and AI-assisted drafting of security questionnaire responses. As of 2026 Vanta reports serving more than 16,000 customers, including Ramp, Cursor, Snowflake, Duolingo, GitHub, and Samsara, and has raised over 500 million dollars in funding, most recently a 150 million dollar Series D in mid-2025 that valued the company at roughly 4.15 billion dollars. Pricing is not publicly listed; third-party sources estimate annual contracts typically range from about 10,000 dollars for smaller Core plans up to 80,000 dollars or more for Scale and Enterprise tiers, with the median deal size cited around 19,000 dollars per year, plus optional add-ons such as vendor risk management. Vanta differs from application security testing tools like Veracode by focusing on organizational compliance and trust posture rather than scanning source code for vulnerabilities.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'afc32d91-8855-4308-bcef-20828d9e78e2';

