-- ── Vector ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Vector is a free, open-source, high-performance observability data pipeline for collecting, transforming, and routing logs, metrics, and traces, originally built by Timber.io and now maintained by Datadog.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$Maintained by Datadog's Community Open Source Engineering team; Datadog has 5,000+ employees$q$, company_size),
  headquarters = COALESCE($q$New York, New York, USA (Datadog)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Vector: Open-Source Observability Data Pipeline$q$, seo_title),
  seo_meta_description = COALESCE($q$Vector is a free, Rust-built, open-source tool for collecting, transforming, and routing logs and metrics, maintained by Datadog. Not a vector database.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Vector is a free, open-source observability data pipeline tool used to collect, transform, and route logs, metrics, and traces between systems, functioning as a vendor-neutral alternative to agents like Logstash, Fluentd, or Fluent Bit. It should not be confused with a vector database used for AI embeddings and similarity search; despite the similar name, Vector is purely a data-pipeline and log-shipping tool with no relation to vector search technology. The project began with its first commits in 2018 at Timber.io, a startup building developer-facing logging tools. Timber.io open-sourced Vector as a lightweight, memory-safe alternative to older log shippers, emphasizing that it was built in Rust for speed and low resource usage, capable of running as a daemon, sidecar, or aggregator across cloud and on-premise environments. In February 2021, Datadog, the publicly traded observability and monitoring company, acquired Timber Technologies specifically to bring Vector into its portfolio, and Vector has since been maintained by Datadog's Community Open Source Engineering team while remaining fully open source and vendor-neutral in the destinations it supports. Vector ships as a single static binary with no external runtime dependencies, and as of recent releases supports dozens of sources, such as Kafka, Kubernetes, and Syslog, transforms for filtering and enriching data, and sinks for routing to destinations including Datadog, Elasticsearch, S3, Splunk, and Prometheus, among many others. The project has attracted a large open-source community, with tens of thousands of GitHub stars, hundreds of contributors, and tens of millions of downloads reported across more than 40 countries. Because Datadog does not restrict Vector to its own platform, teams use it as a cost-efficient, high-throughput layer for building observability pipelines regardless of which monitoring backend they ultimately send data to, competing with tools such as Fluent Bit, Logstash, OpenTelemetry Collector, and Cribl.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8ccfa422-ec09-4a81-8ffc-cee3d57641ca';

