-- ── Vectr ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Vectr is a browser-based vector graphics editor and AI logo maker with real-time collaboration, letting users create and export SVG artwork for free or on paid plans with added AI tools.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $4/month)$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$Small team under Pixlr / Inmagine Group$q$, company_size),
  headquarters = COALESCE($q$Singapore (Pixlr Pte Ltd, part of Inmagine Group)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Vectr: Free Browser-Based Vector Graphics Editor$q$, seo_title),
  seo_meta_description = COALESCE($q$Vectr is a free, browser-based vector graphics and logo design tool with real-time collaboration, SVG export, and optional AI-powered features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Vectr is a browser-based (and formerly desktop) vector graphics editor aimed at beginners and small teams who need a simple, collaborative tool for creating logos, icons, and other SVG artwork without the complexity of professional software like Adobe Illustrator. The product was originally built by Vectr Labs, a startup founded around 2014 by a designer-and-developer pair who wanted a cross-platform, collaborative vector editor; the company raised roughly 910,000 dollars in venture funding, led by Resolute Ventures, and launched out of beta in September 2016. In November 2017, Vectr Labs was acquired by 123RF, a stock media company, and the product has since operated under Pixlr Pte Ltd, a Singapore-based company within the Inmagine Group, which also owns 123RF and the Pixlr photo editor, reflecting a common thread of design and stock-content tools under one corporate umbrella. Vectr's core feature set includes real-time multi-user collaboration with built-in chat, cross-platform syncing between web and desktop, an AI logo maker, image-to-vector (raster-to-SVG) conversion, and export to SVG, PNG, and JPG formats. In more recent years the product has added generative AI tools such as background removal, text-to-vector generation, image enhancement, and object removal, aligning it with the broader shift among lightweight design tools toward AI-assisted workflows. Vectr has historically been positioned as a free alternative to paid vector editors, though it has moved toward a freemium model: a free tier offers limited storage (around 30 MB) and includes ads, while paid Plus and Premium tiers, priced roughly in the 4 to 10 dollar per month range, add more storage, AI credit allowances, and priority support. It competes with other lightweight or free vector tools such as Inkscape, Canva's vector features, and Figma for simple design tasks, though it does not offer the depth of a professional illustration tool like Adobe Illustrator or Affinity Designer.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a4586b52-247b-4d12-87eb-3ffa94cf6ee5';

