-- ── VEED ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$VEED is a browser-based AI video editing and creation platform that lets teams edit footage, add subtitles, generate AI avatars, and translate videos for social media and marketing.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from about $12/month, billed annually)$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$Approximately 190-210 employees$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$VEED: AI-Powered Online Video Editor$q$, seo_title),
  seo_meta_description = COALESCE($q$VEED is a browser-based AI video editor with auto-subtitles, AI avatars, and translation tools. Compare VEED pricing plans and key features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$VEED, also styled VEED.IO, is a browser-based video editing and creation platform that combines a traditional timeline editor with AI-powered tools such as automatic subtitling, AI avatars with voice cloning, background removal, and video translation. It was founded in London in 2018 and bootstrapped its growth without outside funding until February 2022, when it raised a 35 million dollar Series A round led solely by Sequoia Capital, a notable deal because Sequoia was the sole investor in the round. VEED is headquartered in London, United Kingdom, and has grown to roughly 190 to 210 employees spread across Europe, Asia, and North America. As of 2026, third-party estimates put VEED's annual recurring revenue at around 50 million dollars and its valuation at roughly 160 million dollars. The platform is aimed at marketers, content creators, and businesses that need to produce social-ready video without dedicated video editing software or a production team; its customer base reportedly includes large brands such as Amazon, Google, Netflix, Meta, and the BBC using it for internal or marketing video content. Core features include automatic subtitle generation and styling, a library of platform-specific templates for TikTok, Instagram, and YouTube, screen and webcam recording, AI avatars with lip-sync and voice cloning, text-to-video generation from prompts and scripts, background noise reduction, and a brand kit for applying consistent colors, fonts, and logos across videos. VEED offers a free tier with watermarked, lower-resolution exports and short video length limits, and paid tiers, commonly named Lite/Basic, Pro, and Business/Studio, priced from roughly 12 to 70 dollars per user per month depending on billing cycle and resolution/length limits, plus a custom-priced Enterprise tier for larger teams needing 4K exports and unlimited length. VEED competes with other browser-based video tools such as Descript, Kapwing, and CapCut, and, within this directory's later entries, Vidnoz and Vizard, differentiating itself with a broad AI feature set bundled into a single editor rather than a narrower single-purpose tool.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '409ea4dc-896f-4857-8834-ef3e42d8555a';

