-- ── Velociraptor ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Velociraptor is a free, open-source digital forensics and incident response tool for endpoint monitoring, evidence collection, and threat hunting across large fleets of machines.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$Open-source project maintained by Rapid7; Rapid7 has 2,000+ employees$q$, company_size),
  headquarters = COALESCE($q$Boston, Massachusetts, USA (Rapid7)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Velociraptor: Open-Source DFIR and Endpoint Monitoring Tool$q$, seo_title),
  seo_meta_description = COALESCE($q$Velociraptor is a free, open-source digital forensics and incident response tool for endpoint monitoring and threat hunting, maintained by Rapid7.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Velociraptor is a free, open-source endpoint monitoring, digital forensics, and incident response platform used by security teams to collect forensic evidence, continuously monitor endpoint activity, and hunt for threats across large numbers of machines simultaneously. It was created in 2018 by Mike Cohen, an information security specialist who previously worked on digital and memory forensics at the Australian Department of Defence and the Australian Federal Police, and who spent eight years at Google building related forensic tools including GRR and Rekall. Velociraptor grew out of that experience into an independent, community-driven open-source project built around a flexible query language called VQL, the Velociraptor Query Language, which lets responders write custom artifacts to collect very specific forensic data, such as file system metadata, registry entries, process execution history, and event logs, from thousands of endpoints at once. In April 2021, Rapid7, the publicly traded security company best known for products like InsightIDR and Metasploit, acquired Velociraptor. Rapid7 stated at the time that it had no plans to turn Velociraptor into a paid commercial product and would instead continue investing in the open-source community while also drawing on the technology to strengthen its own incident response offerings, and the tool has remained free and open source since the acquisition. Velociraptor is organized around three core capabilities: targeted collection, quickly pulling specific artifacts from one or many hosts; continuous monitoring, streaming endpoint events like file changes and process launches to a central server for historical analysis; and proactive threat hunting, running a library of pre-built and custom forensic artifacts across a fleet to search for indicators of compromise. Because it can query thousands of endpoints in minutes and store results centrally, it is popular with incident responders, threat hunters, and managed detection and response providers as an alternative or complement to commercial EDR platforms, competing loosely with open-source and commercial DFIR tooling such as GRR, Osquery, and various vendor incident response suites. Security teams are advised to keep it updated, since several CVEs, including remote code execution issues, have been disclosed and patched in past releases.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e37166a1-5273-4465-ae0c-fa12188ba286';

