-- ── Veloren ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Veloren is a free, open-source multiplayer voxel action-RPG inspired by Cube World, Minecraft, and Dwarf Fortress, built in Rust by a volunteer community.$q$, short_description),
  pricing_model = COALESCE($q$free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$Volunteer open-source community, approximately 20 active developers and 150+ contributors$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Veloren: Free Open-Source Voxel RPG Game$q$, seo_title),
  seo_meta_description = COALESCE($q$Veloren is a free, open-source multiplayer voxel action-RPG built in Rust, inspired by Cube World and Minecraft, with crafting, dungeons, and mounts.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Veloren is a free, open-source, multiplayer voxel action role-playing game developed entirely by a volunteer community rather than a commercial studio. Development began on May 28, 2018, and the game draws explicit inspiration from Cube World, Minecraft, The Legend of Zelda: Breath of the Wild, and Dwarf Fortress, combining procedurally generated open-world exploration with dynamic combat, crafting, and cooperative multiplayer. Veloren is built with a custom voxel engine written in Rust, structured as a set of modular crates that allow the community to compile and reuse individual engine components independently, and the project is licensed under the GNU General Public License version 3, meaning both its code and its original, community-made graphics, music, and assets are freely available and modifiable. Unlike commercial games, Veloren has no publisher or company behind it; it is coordinated through the VelorenProject organization on GitLab and GitHub by roughly 20 active core developers alongside another 20 or so artists, writers, designers, and composers, with more than 150 total contributors credited over the project's history. Players can explore a fully simulated, procedurally generated fantasy world containing mountains, deserts, and jungles, engage in real-time combat with a variety of weapon types, craft equipment in towns, delve into dungeons with bosses, mine underground cave networks, and tame creatures as companions or mounts, either solo, on public multiplayer servers, or on self-hosted LAN servers. Because it is entirely free and open source with no monetization or in-app purchases of any kind, Veloren is frequently cited in comparisons of free and open-source alternatives to commercial voxel sandbox and survival RPG games, alongside other community-driven titles, and its regular development blog posts and active GitLab repository reflect a still-evolving, pre-1.0 project rather than a finished commercial release.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'bd0b0ec4-080c-44f8-8cca-2ceddee81151';

