-- ── Vendr ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Vendr is a SaaS buying and software pricing intelligence platform that helps finance and procurement teams benchmark prices and negotiate software contracts; it was acquired by Vertice in 2026.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$Approximately 225 employees$q$, company_size),
  headquarters = COALESCE($q$Boston, Massachusetts, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Vendr: SaaS Procurement and Pricing Intelligence Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Vendr helps finance and procurement teams benchmark software prices and negotiate SaaS contracts using data from real B2B transactions.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Vendr is a SaaS buying and software pricing intelligence platform used by finance and procurement teams to benchmark what they should pay for software and to negotiate better terms on new purchases and renewals. The company was started in 2018 and went through Y Combinator's Summer 2019 batch before raising significant venture funding, including a 60 million dollar Series A led by Tiger Global and a 150 million dollar Series B co-led by Craft Ventures and SoftBank Vision Fund, bringing total funding to more than 216 million dollars. Vendr is headquartered in Boston, Massachusetts, with a second office in Charleston, and employs roughly 225 people. Its platform is built on a large proprietary dataset, described by the company as more than 15 billion dollars in verified software spend and over 130,000 real negotiations across more than 4,500 suppliers, which it uses to show buyers fair market pricing before they negotiate. Vendr's product evolved from an initial buyer-side negotiation service, where Vendr's own team negotiated software contracts on behalf of customers, into a broader platform called Vendr 2.0 launched in 2022, and more recently into an AI-driven offering with a Pricing Intelligence Agent that surfaces market benchmarks and a Negotiation Agent that can conduct supplier email negotiations with reported success rates around 87 percent. The company reports over 1.4 billion dollars in cumulative customer savings and more than 5,000 finance and procurement teams as users, with reported 2024 annual recurring revenue of around 94.8 million dollars and a valuation near 1 billion dollars. In a significant industry consolidation, Vendr was acquired by Vertice, a competing SaaS spend management platform, effective June 1, 2026, combining the two companies' software pricing benchmarking and negotiation capabilities under one roof. Vendr's pricing for its own platform is not publicly listed and is sold through custom quotes based on a customer's software spend under management, similar to peers such as Zylo and Tropic in the SaaS spend management category.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '47c26ff2-e8f9-4fe3-9718-d79f6a0f9407';

